  // Get pending exceptions
  const pending = await db.select()
    .from(dcgPendingExceptions)
    .where(eq(dcgPendingExceptions.agentId, `sweep:${sessionId}`));

  return c.json({
    blocks: blocks.length,
    pending: pending.filter(p => p.status === "pending").length,
    approved: pending.filter(p => p.status === "approved").length,
    denied: pending.filter(p => p.status === "denied").length,
    blockDetails: blocks,
    pendingDetails: pending,
  });
});
