```sql
CREATE TABLE dcg_allowlist (
  id UUID PRIMARY KEY,
  pattern TEXT NOT NULL,
  match_type VARCHAR(50) NOT NULL,
  scope VARCHAR(50) NOT NULL,
  scope_id UUID,
  reason TEXT,
  created_by UUID REFERENCES users(id),
  created_at TIMESTAMP DEFAULT NOW(),
  expires_at TIMESTAMP,
  usage_count INTEGER DEFAULT 0
);

CREATE TABLE dcg_feedback (
  id UUID PRIMARY KEY,
  blocked_content TEXT NOT NULL,
  block_reason TEXT NOT NULL,
  pack_id VARCHAR(255),
  submitted_by UUID REFERENCES users(id),
  submitted_at TIMESTAMP DEFAULT NOW(),
  status VARCHAR(50) DEFAULT 'pending',
  reviewed_by UUID REFERENCES users(id),
  reviewed_at TIMESTAMP,
  resolution VARCHAR(50),
  notes TEXT
);

CREATE TABLE dcg_packs (
  id VARCHAR(255) PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  description TEXT,
  version VARCHAR(50),
  rule_count INTEGER,
  enabled BOOLEAN DEFAULT true,
  priority INTEGER DEFAULT 0,
  scope VARCHAR(50) DEFAULT 'system'
);

CREATE TABLE dcg_block_events (
  id UUID PRIMARY KEY,
  content_hash VARCHAR(64),
  rule_id VARCHAR(255),
  pack_id VARCHAR(255),
  agent_id UUID,
  repository_id UUID,
  blocked_at TIMESTAMP DEFAULT NOW(),
  metadata JSONB
);

CREATE INDEX idx_block_events_time ON dcg_block_events(blocked_at);
CREATE INDEX idx_block_events_pack ON dcg_block_events(pack_id);
CREATE INDEX idx_feedback_status ON dcg_feedback(status);
